/-
Let $R(k)$ mean the *diagonal* Ramsey number $R(k,k)$: the smallest $n$ such that **every** red/blue coloring of the edges of (K_n) contains a monochromatic (K_k).
-/
open SimpleGraph

/-- `IsRamsey k n` means that for every graph on `n` vertices,
either the graph has a clique of size `k` or its complement has a clique of size `k`.
This corresponds to every 2-coloring of the edges of K_n having a monochromatic K_k. -/
def IsRamsey (k n : ℕ) : Prop :=
  ∀ (G : SimpleGraph (Fin n)), (∃ (s : Finset (Fin n)), G.IsNClique k s) ∨ (∃ (s : Finset (Fin n)), Gᶜ.IsNClique k s)

/-- The diagonal Ramsey number `R(k)` is the smallest `n` such that `IsRamsey k n`. -/
noncomputable def diagonalRamsey (k : ℕ) : ℕ :=
  sInf { n | IsRamsey k n }

