  · rw [ show ( 5 / 2 : ℝ ) = 2 + 1 / 2 by norm_num, Real.rpow_add ] <;> norm_num;
    rw [ ← Real.sqrt_eq_rpow ] ; nlinarith [ Real.sqrt_nonneg 2, Real.sq_sqrt zero_le_two ];
