    rw [ show ( 1 + ( ( k : ℝ ) + 1 ) / 2 ) = ( 1 + ( k : ℝ ) / 2 ) + 1 / 2 by ring, Real.rpow_add ] <;> norm_num ; ring_nf ; norm_num;
