/-
If `IsRamsey k n` holds and `n \le m`, then `IsRamsey k m` holds.
-/
lemma IsRamsey.mono {k n m : ℕ} (hnm : n ≤ m) (h : IsRamsey k n) : IsRamsey k m := by
  intro G;
  obtain h | h := h ( G.comap ( Fin.castLE hnm ) ) <;> [ left; right ] <;> obtain ⟨ s, hs ⟩ := h <;> use s.image ( Fin.castLE hnm ) <;> simp_all +decide [ SimpleGraph.isNClique_iff ];
  · simp_all +decide [ Set.Pairwise ];
    rw [ Finset.card_image_of_injective _ fun x y hxy => by simpa [ Fin.ext_iff ] using hxy, hs.2 ];
  · simp_all +decide [ SimpleGraph.IsIndepSet, Finset.card_image_of_injective, Function.Injective ];
    intro v hv w hw hvw; aesop;

