/-
$R(k) > (\sqrt{2})^k$ for $k \ge 3$.
-/
theorem diagonalRamsey_gt_sqrt2_pow_k (k : ℕ) (hk : 3 ≤ k) (h_ramsey : ∃ M, IsRamsey k M) :
    (diagonalRamsey k : ℝ) > (Real.sqrt 2) ^ k := by
      -- Let $n = \lfloor 2^{k/2} \rfloor$. We show that `IsRamsey k n` is false.
      have probabilistic_bound : ¬IsRamsey k (Nat.floor ((Real.sqrt 2) ^ k)) := by
        unfold IsRamsey;
        push_neg;
        have := probabilistic_bound ⌊ ( Real.sqrt 2 ) ^ k⌋₊ k ( by simpa using probabilistic_condition k hk );
        obtain ⟨ G, hG₁, hG₂ ⟩ := this;
        refine' ⟨ G, fun s hs => _, fun s hs => _ ⟩;
        · exact hG₁ s hs.card_eq hs;
        · exact hG₂ s ( by simpa [ SimpleGraph.isNClique_iff ] using hs.2 ) hs;
      -- By definition of $R(k)$, if $R(k) \leq \lfloor 2^{k/2} \rfloor$, then `IsRamsey k (⌊2^{k/2}⌋)` would be true.
      have h_inf : diagonalRamsey k > Nat.floor ((Real.sqrt 2) ^ k) := by
        exact lt_of_not_ge fun h => probabilistic_bound <| Nat.sInf_mem h_ramsey |> fun h' => IsRamsey.mono h h';
      exact Nat.lt_of_floor_lt h_inf
